import React from "react";
import { Outlet, Link, useLocation } from "react-router-dom";

const AdminLayout = () => {
  const location = useLocation();

  const navItems = [
    { name: "Tổng quan", path: "/admin/dashboard", icon: "📊" },
    { name: "Quản lý sản phẩm", path: "/admin/products", icon: "🛍️" },
    { name: "Quản lý đơn hàng", path: "/admin/orders", icon: "📦" },
    { name: "Quản lý danh mục", path: "/admin/categories", icon: "🗂️" },
    { name: "Quản lý người dùng", path: "/admin/users", icon: "👤" },

    // ⭐ NEW — EMAIL MARKETING
    { name: "Gửi Email", path: "/admin/email", icon: "📩" },
  ];

  return (
    <div className="flex min-h-screen font-sans bg-[#fff] text-[14px] leading-relaxed text-[#3e2f2f]">
      {/* Sidebar */}
      <aside className="fixed left-0 top-0 bottom-0 w-56 bg-[#f9f5f1] border-r border-[#e4c6ba] flex flex-col shadow-sm z-50">
        
        {/* Logo */}
        <Link
          to="/"
          className="flex items-center gap-3 p-4 border-b border-[#e4c6ba] hover:bg-[#e06c7f22] transition"
        >
          <div className="w-10 h-10 rounded-full bg-[#e06c7f] flex items-center justify-center text-white font-bold shadow-md">
            A
          </div>
          <div>
            <p className="text-sm font-semibold text-[#3e2f2f]">Admin</p>
            <p className="text-xs text-[#8b5e3c] font-medium">DTP Flower</p>
          </div>
        </Link>

        {/* Navigation */}
        <nav className="flex flex-col gap-1 p-2 flex-1">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm transition-all duration-200 ${
                location.pathname === item.path
                  ? "bg-[#e06c7f33] text-[#3e2f2f] font-semibold border-l-4 border-[#e06c7f]"
                  : "text-[#3e2f2f99] hover:bg-[#e06c7f22] hover:text-[#3e2f2f]"
              }`}
            >
              <span>{item.icon}</span>
              {item.name}
            </Link>
          ))}
        </nav>

        {/* Xem trang web */}
        <div className="p-3">
          <a
            href="/"
            className="block text-center bg-[#8b5e3c] text-white py-2 rounded-md text-sm font-semibold hover:bg-[#a56c44] transition"
          >
            🌸 Xem trang web
          </a>
        </div>
      </aside>

      {/* Main content */}
      <main className="flex-1 ml-56 p-6 overflow-y-auto transition-colors duration-300">
        <div className="p-5 rounded-xl shadow-md min-h-[70vh] bg-white border border-[#e4c6ba]">
          <Outlet />
        </div>
      </main>
    </div>
  );
};

export default AdminLayout;
